previewCss:
.darma-loader-uiverse-ruby-pinwheel-prism {
  position: relative;
  width: 0;
  height: 0;
  border: 24px solid;
  border-color: var(--loader-color, #ff3b3b) transparent var(--loader-color, #ff3b3b) transparent;
  animation: darma-loader-uiverse-ruby-pinwheel-prism-rubyPinwheelSpin 2s linear infinite;
}
.darma-loader-uiverse-ruby-pinwheel-prism::before,
.darma-loader-uiverse-ruby-pinwheel-prism::after {
  content: "";
  display: block;
  border: 24px solid transparent;
  border-left-color: var(--loader-color, #ff3b3b);
  position: absolute;
  left: -24px;
  top: -24px;
  animation: darma-loader-uiverse-ruby-pinwheel-prism-rubyPinwheelFold 1s infinite ease-in;
  transform-origin: 0% 100%;
}
.darma-loader-uiverse-ruby-pinwheel-prism::before {
  border-color: transparent var(--loader-color, #ff3b3b) transparent transparent;
  transform-origin: 100% 0%;
  animation-delay: 0.5s;
}
@keyframes darma-loader-uiverse-ruby-pinwheel-prism-rubyPinwheelSpin { to { transform: rotate(360deg); } }
@keyframes darma-loader-uiverse-ruby-pinwheel-prism-rubyPinwheelFold { 20%, 80% { transform: rotate(0); } 50% { transform: rotate(-90deg); } }

